要在表格下方加入保存按钮，可以使用 <template> 标签中的 slot 插槽来实现。示例代码如下：

```
<template>
  <div>
    <vxe-table :data="tableData" :edit-config="{trigger: 'click', mode: 'cell'}">
      <vxe-column field="khxh__c" min-width="120" title="客户型号"></vxe-column>
      <vxe-column field="main_field" min-width="100" title="mzgcpck" editable></vxe-column>
    </vxe-table>
    <div class="button-group">
      <button type="button" class="btn btn-primary" @click="saveTableData">保存</button>
    </div>
  </div>
</template>
```

在代码中，使用了一个 div 包裹了表格和保存按钮，并在按钮下方插入了样式为 "button-group" 的 div，用于控制样式。

接下来，需要在 Vue 实例中编写 saveTableData 方法，用于保存修改后的表格数据。具体实现代码如下：

```
<script>
export default {
  data() {
    return {
      tableData: [...], // 表格数据
    }
  },
  methods: {
    saveTableData() {
      console.log(this.tableData); // 保存修改后的表格数据
    },
  },
};
</script>
```

在 saveTableData 方法中，可以将修改后的表格数据通过接口等方式提交到服务器，或直接在前端进行处理和保存。这里只是简单输出表格数据，供参考。

可以使用作用域插槽中的 formatter 方法来计算数量1和数量2的差值，并将其显示在“差异”列中。

首先，需要在 <vxe-column> 中加入 formatter 属性，同时在作用域插槽中编写 formatter 方法。同时，需要在 data() 中添加差异列的数据。

示例代码如下：

```
<template>
  <vxe-table :data="tableData">
    <vxe-column field="sl__c" width="100" title="数量1" sortable :edit-render="{autofocus: '.vxe-input--inner', defaultValue: '11'}">
      <template #edit="{ row }">
        <vxe-input v-model="row.sl__c" type="text"></vxe-input>
      </template>
    </vxe-column>
    <vxe-column field="sl__c_2" width="100" title="数量2" sortable :edit-render="{autofocus: '.vxe-input--inner', defaultValue: '11'}">
      <template #edit="{ row }">
        <vxe-input v-model="row.sl__c_2" type="text"></vxe-input>
      </template>
    </vxe-column>
    <vxe-column field="cy" width="100" title="差异" :formatter="formatter"></vxe-column>
  </vxe-table>
</template>

<script>
export default {
  data() {
    return {
      tableData: [
        { sl__c: 10, sl__c_2: 6, cy: 4 },
        { sl__c: 7, sl__c_2: 8, cy: -1 },
        ...
      ],
    };
  },
  methods: {
    formatter({cellValue, row}) {
      return row.sl__c - row.sl__c_2;
    },
  },
};
</script>
```

在代码中，formatter 方法中通过 row 中的 sl__c 和 sl__c_2 字段计算出差值，并将其作为 formatter 方法的返回值。在 <vxe-column> 中设置 formatter 属性后，会自动调用该方法来渲染该列的数据，从而展示出数量1和数量2的差异。

默认情况下，修改数量1后并不会自动触发 formatter 方法，因为该方法是在表格数据发生变化时才会被调用的。但是，可以使用 @update:data 属性来监听数据更新事件，从而在数据发生变化时手动调用 formatter 方法。

示例代码如下：

```
<template>
  <vxe-table :data="tableData" @update:data="onUpdateData">
    <vxe-column field="sl__c" width="100" title="数量1" sortable :edit-render="{autofocus: '.vxe-input--inner', defaultValue: '11'}">
      <template #edit="{ row }">
        <vxe-input v-model="row.sl__c" type="text"></vxe-input>
      </template>
    </vxe-column>
    <vxe-column field="sl__c_2" width="100" title="数量2" sortable :edit-render="{autofocus: '.vxe-input--inner', defaultValue: '11'}">
      <template #edit="{ row }">
        <vxe-input v-model="row.sl__c_2" type="text"></vxe-input>
      </template>
    </vxe-column>
    <vxe-column field="cy" width="100" title="差异" :formatter="formatter"></vxe-column>
  </vxe-table>
</template>

<script>
export default {
  data() {
    return {
      tableData: [
        { sl__c: 10, sl__c_2: 6, cy: 4 },
        { sl__c: 7, sl__c_2: 8, cy: -1 },
        ...
      ],
    };
  },
  methods: {
    formatter({cellValue, row}) {
      return row.sl__c - row.sl__c_2;
    },
    onUpdateData(data) {
      // 在数据发生变化时手动调用 formatter 方法
      data.forEach(row => {
        row.cy = this.formatter({cellValue: null, row});
      });
    },
  },
};
</script>
```

在代码中，使用 @update:data 属性监听表格数据更新事件，然后使用 onUpdateData 方法手动调用 formatter 方法，重新计算数量1和数量2的差值，并将其赋值给该列的数据。这样一来，修改数量1后会自动计算数量1和数量2的差异，并展示在“差异”列中。

可以通过监听单元格事件来实现，在编辑数量1单元格时，触发同步修改其他行的数据。

示例代码如下：

```
<template>
  <vxe-table :data="tableData" @edit-closed="onEditClosed">
    <vxe-column field="sl__c" width="100" title="数量1" sortable :edit-render="{autofocus: '.vxe-input--inner'}">
      <template #edit="{ row }">
        <vxe-input v-model="row.sl__c" type="text"></vxe-input>
      </template>
    </vxe-column>
    <vxe-column field="sl__c_2" width="100" title="数量2" sortable :edit-render="{autofocus: '.vxe-input--inner'}">
      <template #edit="{ row }">
        <vxe-input v-model="row.sl__c_2" type="text"></vxe-input>
      </template>
    </vxe-column>
    <vxe-column field="cy" width="100" title="差异" :formatter="formatter"></vxe-column>
  </vxe-table>
</template>

<script>
export default {
  data() {
    return {
      tableData: [
        { sl__c: 10, sl__c_2: 6, cy: 4 },
        { sl__c: 7, sl__c_2: 8, cy: -1 },
        ...
      ],
    };
  },
  methods: {
    formatter({cellValue, row}) {
      return row.sl__c - row.sl__c_2;
    },
    onEditClosed({row, column}) {
      if (column.property === 'sl__c') {
        this.syncData(row, 'sl__c');
      }
    },
    syncData(row, field) {
      // 遍历改变数量1的单元格所在的行，同步修改其他行的对应单元格数据
      this.tableData.forEach(item => {
        if (item.id !== row.id) { // 排除当前行
          item[field] = row[field];
          item.cy = this.formatter({cellValue: null, row: item}); // 更新差异列
        }
      });
    },
  },
};
</script>
```

在代码中，使用 @edit-closed 属性监听单元格编辑结束事件，在 onEditClosed 方法中判断当前编辑的单元格是否为数量1单元格（即 column.property 是否等于 'sl__c'），如果是，则调用 syncData 方法进行同步修改其他行的数据。

在 syncData 方法中，首先遍历整个表格数据，排除当前行，然后同步修改其他行的对应单元格数据。最后，更新差异列的数据。

这样一来，当修改数量1的单元格数据时，其他行对应的单元格数据也会被同步修改，并更新差异列的数据。

可以使用 Element UI 的 MessageBox 组件来实现弹窗提醒功能。在 recordSearch 方法中，在异步操作开始和结束时，分别调用 MessageBox 的 loading 和 close 方法。MessageBox 的具体使用方式可以参考 Element UI 官方文档。

示例代码如下：

```
<template>
  <el-button :loading="loading" @click="recordSearch()" size="mini" style="margin-left: 50px;" type="primary">
    查询
  </el-button>
</template>

<script>
import { MessageBox } from 'element-ui';

export default {
  data() {
    return {
      loading: false,
    };
  },
  methods: {
    async recordSearch() {
      try {
        // 开始异步操作时，调用MessageBox的loading方法显示加载中动画
        this.loading = true;
        await axios.get('http://xxx.com/data');
        // 异步操作完成后，调用MessageBox的close方法关闭加载中动画，并弹出成功提示框
        this.loading = false;
        MessageBox.alert('查询成功', '提示');
      } catch (error) {
        // 异步操作出错后，调用MessageBox的close方法关闭加载中动画，并弹出错误提示框
        this.loading = false;
        MessageBox.alert('查询失败', '提示');
      }
    },
  },
};
</script>
```

在代码中，使用 MessageBox 的 loading 和 close 方法分别实现加载中动画和弹窗提示功能。在 recordSearch 方法中，在异步操作开始时，调用 MessageBox 的 loading 方法显示加载中动画；在异步操作完成后，调用 MessageBox 的 close 方法关闭加载中动画，并根据结果弹出成功或失败的提示框。

可以使用 Element UI 的 MessageBox 组件来实现弹窗同步功能。在 recordSearch 方法中，在点击同步按钮时，调用 MessageBox 的 confirm 方法弹出确认框。如果用户点击了确认按钮，再执行相应的同步操作；如果用户点击了取消按钮，就不做任何操作。

示例代码如下：

```
<template>
  <el-button :loading="loading" @click="recordSearch()" size="mini" style="margin-left: 50px;" type="primary">
    同步
  </el-button>
</template>

<script>
import { MessageBox } from 'element-ui';

export default {
  data() {
    return {
      loading: false,
    };
  },
  methods: {
    async recordSearch() {
      try {
        // 弹出确认框
        const confirmResult = await MessageBox.confirm('确定要同步数据吗？', '提示', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning',
        });
        if (confirmResult === 'confirm') { // 如果用户点击了确认按钮
          // 开始异步操作时，调用MessageBox的loading方法显示加载中动画
          this.loading = true;
          await axios.post('http://xxx.com/sync');
          // 异步操作完成后，调用MessageBox的close方法关闭加载中动画，并弹出成功提示框
          this.loading = false;
          MessageBox.alert('同步成功', '提示');
        }
      } catch (error) {
        // 异步操作出错后，调用MessageBox的close方法关闭加载中动画，并弹出错误提示框
        this.loading = false;
        MessageBox.alert('同步失败', '提示');
      }
    },
  },
};
</script>
```

在代码中，使用 MessageBox 的 confirm 方法实现弹窗确认功能。在 recordSearch 方法中，点击同步按钮时，调用 MessageBox 的 confirm 方法弹出确认框，等待用户点击按钮。如果用户点击了确认按钮，就执行相应的异步操作；如果用户点击了取消按钮，不做任何操作。其中，MessageBox.confirm 方法的第三个参数可选，可以用来设置弹窗上按钮的文案、类型等信息。
